package com.finguard.audit.api;import com.finguard.audit.service.AuditService;import org.springframework.security.access.prepost.PreAuthorize;import org.springframework.web.bind.annotation.*;import java.util.*;
@RestController @RequestMapping("/api/audit") @PreAuthorize("hasRole('ADMIN')") public class AuditController {private final AuditService service;public AuditController(AuditService service){this.service=service;}@GetMapping public List<AuditEventResponse> recent(){return service.recent().stream().map(AuditEventResponse::from).toList();}@GetMapping("/transactions/{id}")public List<AuditEventResponse> byTransaction(@PathVariable UUID id){return service.byTransaction(id).stream().map(AuditEventResponse::from).toList();}}
